import{_ as a,c as e,o,a1 as r}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"介绍: 本地 AI 网关 | Antigravity Manager","description":"了解 Antigravity Manager 的核心定位。它提供桌面端和本地 HTTP 网关，支持多协议端点和账号池调度，帮助你快速上手本地反代并避免常见配置错误。","frontmatter":{"title":"介绍: 本地 AI 网关 | Antigravity Manager","sidebarTitle":"什么是本地 AI 网关","subtitle":"Antigravity Tools 是什么：把「账号 + 协议」做成本地 AI 网关","description":"了解 Antigravity Manager 的核心定位。它提供桌面端和本地 HTTP 网关，支持多协议端点和账号池调度，帮助你快速上手本地反代并避免常见配置错误。","tags":["入门","概念","本地网关","API Proxy"],"prerequisite":[],"order":1},"headers":[],"relativePath":"zh/lbjlaq/Antigravity-Manager/start/getting-started/index.md","filePath":"zh/lbjlaq/Antigravity-Manager/start/getting-started/index.md"}'),l={name:"zh/lbjlaq/Antigravity-Manager/start/getting-started/index.md"};function i(d,t,n,s,c,h){return o(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="antigravity-tools-是什么-把-账号-协议-做成本地-ai-网关" tabindex="-1">Antigravity Tools 是什么：把“账号 + 协议”做成本地 AI 网关 <a class="header-anchor" href="#antigravity-tools-是什么-把-账号-协议-做成本地-ai-网关" aria-label="Permalink to &quot;Antigravity Tools 是什么：把“账号 + 协议”做成本地 AI 网关&quot;">​</a></h1><p>很多 AI 客户端/SDK 的接入门槛，不在“会不会调用 API”，而在“你到底要对接哪家协议、怎么管理多个账号、怎么让失败自动恢复”。Antigravity Tools 试图把这三件事，收敛成一个本地网关。</p><h2 id="什么是-antigravity-tools" tabindex="-1">什么是 Antigravity Tools？ <a class="header-anchor" href="#什么是-antigravity-tools" aria-label="Permalink to &quot;什么是 Antigravity Tools？&quot;">​</a></h2><p><strong>Antigravity Tools</strong> 是一个桌面应用：你在 GUI 里管理账号与配置，它在本机启动一个 HTTP 反代服务，把不同厂商/协议的请求统一转发到上游，并把响应再转换回客户端熟悉的格式。</p><h2 id="学完你能做什么" tabindex="-1">学完你能做什么 <a class="header-anchor" href="#学完你能做什么" aria-label="Permalink to &quot;学完你能做什么&quot;">​</a></h2><ul><li>说清楚 Antigravity Tools 解决的是什么问题（以及它不解决什么）</li><li>认清它的核心组成：GUI、账号池、HTTP 反代网关、协议适配</li><li>了解默认安全边界（127.0.0.1、端口、鉴权模式）以及什么情况下需要改</li><li>知道下一步该去哪一章：安装、添加账号、启动反代、接入客户端</li></ul><h2 id="你现在的困境" tabindex="-1">你现在的困境 <a class="header-anchor" href="#你现在的困境" aria-label="Permalink to &quot;你现在的困境&quot;">​</a></h2><p>你可能遇到过这些麻烦：</p><ul><li>同一个客户端要支持 OpenAI/Anthropic/Gemini 三种协议，配置经常写乱</li><li>有多个账号，但切换、轮换、限流重试都靠手动</li><li>请求失败时，你只能盯日志猜是“账号失效”还是“上游限流/容量耗尽”</li></ul><p>Antigravity Tools 的目标是把这些“边角工作”做进一个本地网关里，让你的客户端/SDK 尽量只关心一件事：把请求发到本地。</p><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><p>你可以把它理解成一套本地的「AI 调度网关」，由三层组成：</p><ol><li>GUI（桌面应用）</li></ol><ul><li>负责让你管理账号、配置、监控与统计。</li><li>主页面包含：Dashboard、Accounts、API Proxy、Monitor、Token Stats、Settings。</li></ul><ol start="2"><li>HTTP 反代服务（Axum Server）</li></ol><ul><li>负责对外暴露多个协议的端点，并把请求转交给对应 handler。</li><li>反代服务会挂载鉴权、中间件监控、CORS、Trace 等层。</li></ul><ol start="3"><li>账号池与调度（TokenManager 等）</li></ol><ul><li>负责从本地账号池中挑选可用账号，必要时刷新 token、做轮换与自愈。</li></ul><div class="info custom-block"><p class="custom-block-title">“本地网关”是什么意思？</p><p>这里的“本地”是字面意思：服务跑在你自己的机器上，你的客户端（Claude Code、OpenAI SDK、各类第三方客户端）把 Base URL 指向 <code>http://127.0.0.1:&lt;port&gt;</code>，请求先到本机，再由 Antigravity Tools 转发到上游。</p></div><h2 id="它对外提供哪些端点" tabindex="-1">它对外提供哪些端点 <a class="header-anchor" href="#它对外提供哪些端点" aria-label="Permalink to &quot;它对外提供哪些端点&quot;">​</a></h2><p>反代服务在一个 Router 里注册了多套协议端点，你可以先记住这几个“入口”：</p><ul><li>OpenAI 兼容：<code>/v1/chat/completions</code>、<code>/v1/completions</code>、<code>/v1/responses</code>、<code>/v1/models</code></li><li>Anthropic 兼容：<code>/v1/messages</code>、<code>/v1/messages/count_tokens</code></li><li>Gemini 原生：<code>/v1beta/models</code>、<code>/v1beta/models/:model</code>、<code>/v1beta/models/:model/countTokens</code></li><li>健康检查：<code>GET /healthz</code></li></ul><p>如果你的客户端能对接其中任意一种协议，理论上都可以通过“改 Base URL”的方式，把请求导到这个本地网关。</p><h2 id="默认安全边界-别跳过" tabindex="-1">默认安全边界（别跳过） <a class="header-anchor" href="#默认安全边界-别跳过" aria-label="Permalink to &quot;默认安全边界（别跳过）&quot;">​</a></h2><p>这类“本地反代”最大的坑，往往不是功能不够，而是你不小心把它暴露出去了。</p><p>先记住几条默认值（都来自默认配置）：</p><ul><li>默认端口：<code>8045</code></li><li>默认仅本机访问：<code>allow_lan_access=false</code>，监听地址为 <code>127.0.0.1</code></li><li>默认鉴权模式：<code>auth_mode=off</code>（不要求客户端带 key）</li><li>默认会生成一个 <code>sk-...</code> 形式的 <code>api_key</code>（供你在需要鉴权时开启）</li></ul><div class="warning custom-block"><p class="custom-block-title">什么时候必须开鉴权？</p><p>只要你开启了局域网访问（<code>allow_lan_access=true</code>，监听地址变为 <code>0.0.0.0</code>），就应该同时启用鉴权，并把 API Key 当作密码管理。</p></div><h2 id="什么时候用-antigravity-tools" tabindex="-1">什么时候用 Antigravity Tools <a class="header-anchor" href="#什么时候用-antigravity-tools" aria-label="Permalink to &quot;什么时候用 Antigravity Tools&quot;">​</a></h2><p>它更适合这类场景：</p><ul><li>你有多个 AI 客户端/SDK，希望统一走一个 Base URL</li><li>你需要把不同协议（OpenAI/Anthropic/Gemini）收敛到同一套“本地出口”</li><li>你有多个账号，希望由系统负责轮换与稳定性处理</li></ul><p>如果你只想“写两行代码直接调官方 API”，并且账号/协议都很固定，那它可能有点重。</p><h2 id="跟我做-先建立一个正确的使用顺序" tabindex="-1">跟我做：先建立一个正确的使用顺序 <a class="header-anchor" href="#跟我做-先建立一个正确的使用顺序" aria-label="Permalink to &quot;跟我做：先建立一个正确的使用顺序&quot;">​</a></h2><p>这节课不教你细节配置，只把主线顺序先对齐，避免你跳着用导致卡住：</p><h3 id="第-1-步-先安装再启动" tabindex="-1">第 1 步：先安装再启动 <a class="header-anchor" href="#第-1-步-先安装再启动" aria-label="Permalink to &quot;第 1 步：先安装再启动&quot;">​</a></h3><p><strong>为什么</strong> 桌面端负责账号管理与启动反代服务，没有它，后续的 OAuth/反代都无从谈起。</p><p>去下一章按 README 的安装方式完成安装。</p><p><strong>你应该看到</strong>：你能打开 Antigravity Tools，并看到 Dashboard 页面。</p><h3 id="第-2-步-添加至少一个账号" tabindex="-1">第 2 步：添加至少一个账号 <a class="header-anchor" href="#第-2-步-添加至少一个账号" aria-label="Permalink to &quot;第 2 步：添加至少一个账号&quot;">​</a></h3><p><strong>为什么</strong> 反代服务需要从账号池里拿到可用身份去向上游发请求；没有账号，网关也无法“代你调用”。</p><p>去「添加账号」那一章，按 OAuth 或 Refresh Token 流程把账号加进来。</p><p><strong>你应该看到</strong>：Accounts 页面里出现你的账号，并能看到配额/状态信息。</p><h3 id="第-3-步-启动-api-proxy-并用-healthz-做最小验证" tabindex="-1">第 3 步：启动 API Proxy，并用 /healthz 做最小验证 <a class="header-anchor" href="#第-3-步-启动-api-proxy-并用-healthz-做最小验证" aria-label="Permalink to &quot;第 3 步：启动 API Proxy，并用 /healthz 做最小验证&quot;">​</a></h3><p><strong>为什么</strong> 先用 <code>GET /healthz</code> 验证“本地服务在跑”，再去接入客户端，排障会简单很多。</p><p>去「启动本地反代并接入第一个客户端」那一章完成闭环。</p><p><strong>你应该看到</strong>：你的客户端/SDK 能通过本地 Base URL 成功拿到响应。</p><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><table tabindex="0"><thead><tr><th>场景</th><th>你可能会怎么做（❌）</th><th>推荐做法（✓）</th></tr></thead><tbody><tr><td>想让手机/另一台电脑访问</td><td>直接打开 <code>allow_lan_access=true</code> 但不设鉴权</td><td>同时启用鉴权，并先在局域网里验证 <code>GET /healthz</code></td></tr><tr><td>客户端报 404</td><td>只改 host/port，不管客户端如何拼接 <code>/v1</code></td><td>先确认客户端的 base_url 拼接策略，再决定是否需要带 <code>/v1</code> 前缀</td></tr><tr><td>一上来就排 Claude Code</td><td>直接接入复杂客户端，失败后不知道从哪查</td><td>先跑通最小闭环：启动 Proxy -&gt; <code>GET /healthz</code> -&gt; 再接入客户端</td></tr></tbody></table><h2 id="本课小结" tabindex="-1">本课小结 <a class="header-anchor" href="#本课小结" aria-label="Permalink to &quot;本课小结&quot;">​</a></h2><ul><li>Antigravity Tools 的定位是“桌面端 + 本地 HTTP 反代网关”：GUI 管理，Axum 提供多协议端点</li><li>你需要把它当作一个本地基础设施：先安装、再加账号、再启动 Proxy、最后接入客户端</li><li>默认只监听 <code>127.0.0.1:8045</code>，如果要暴露到局域网，务必同时启用鉴权</li></ul><h2 id="下一课预告" tabindex="-1">下一课预告 <a class="header-anchor" href="#下一课预告" aria-label="Permalink to &quot;下一课预告&quot;">​</a></h2><blockquote><p>下一课我们把安装这一步走完：<strong><a href="./../installation/">安装与升级：桌面端最佳安装路径</a></strong>。</p><p>你会学到：</p><ul><li>README 里列出的几种安装方式（以及优先级）</li><li>升级入口与常见系统拦截的处理方式</li></ul></blockquote><hr><h2 id="附录-源码参考" tabindex="-1">附录：源码参考 <a class="header-anchor" href="#附录-源码参考" aria-label="Permalink to &quot;附录：源码参考&quot;">​</a></h2><details><summary><strong>点击展开查看源码位置</strong></summary><blockquote><p>更新时间：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>文件路径</th><th>行号</th></tr></thead><tbody><tr><td>产品定位（本地 AI 中转站/协议鸿沟）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/README.md#L35-L77" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>35-77</td></tr><tr><td>Router 端点总览（OpenAI/Claude/Gemini/healthz）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/server.rs#L120-L194" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/server.rs</code></a></td><td>120-194</td></tr><tr><td>默认端口/默认仅本机/默认 key 与 bind address 逻辑</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L174-L291" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a></td><td>174-291</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>GUI 页面路由结构（Dashboard/Accounts/API Proxy/Monitor/Token Stats/Settings）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/App.tsx#L19-L48" target="_blank" rel="noreferrer"><code>src/App.tsx</code></a></td><td>19-48</td></tr></tbody></table><p><strong>关键默认值</strong>：</p><ul><li><code>ProxyConfig.port = 8045</code>：反代服务默认端口</li><li><code>ProxyConfig.allow_lan_access = false</code>：默认仅本机访问</li><li><code>ProxyAuthMode::default() = off</code>：默认不要求鉴权</li></ul></details>',55)])])}const g=a(l,[["render",i]]);export{u as __pageData,g as default};
